import{_ as n,o as i,c as s,ag as r}from"./chunks/framework.DXGyWiRo.js";const t="/images/uebung067.jpg",g=JSON.parse('{"title":"Übung Lektion 41","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung41.md","filePath":"lektionen/uebung41.md"}'),a={name:"lektionen/uebung41.md"};function u(h,e,d,l,o,c){return i(),s("div",null,[...e[0]||(e[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-41" tabindex="-1">Übung Lektion 41 <a class="header-anchor" href="#ubung-lektion-41" aria-label="Permalink to &quot;Übung Lektion 41&quot;">​</a></h1><p>A) Übersetzen Sie die beiden Sprichwörter am Anfang der Lektion.</p><blockquote><p>पुस्तकस्था च या विद्या<br> परहस्ते च यद्धनम् ।<br> कार्यकाले समुत्पन्ने<br> न सा विद्या न तद्धनम् ॥१॥</p><p>Wissen, das in Büchern steht, Geld, das in anderer Hand ist : wenn man es braucht, dann ist das kein Wissen und kein Geld.</p><p>उपदेशो हि मूर्खाणां<br> प्रकोपाय न शान्तये ।<br> पयःपानं भुजङ्गानां<br> केवलं विषवर्धनम् ॥२॥</p><p>Unterricht von Dummköpfen führt zu Aggression, nicht zu Frieden. Wenn man Schlangen Milch zu trinken gibt, vermehrt das nur ihr Gift.</p></blockquote><p>B) Übersetzen Sie:</p><p>बुद्धम् शरणं गच्छामि धर्मं शरणं गच्छामि सङ्घं शरणं गच्छामीति बुद्धगतैर्वक्तव्यम् ॥१॥</p><p>Wer zu Buddha gegangen ist, soll sprechen: &quot;Ich nehme meine Zuflucht zu Buddha, ich nehme meine Zuflucht zur Buddhalehre, ich nehme meine Zuflucht zur Gemeinschaft der durch die Buddhalehre zur Erlösung gelangten.&quot;</p><blockquote><p>Diese dreifache Zuflucht ist äußerst wichtig, um auf dem Weg zur Erlösung die nötige Motivation, Energie und Ausdauer zu haben.</p><p>Es gab und gibt ja eine unüberschaubare Zahl von Weisheitslehrern und Religionsstiftern. Es ist unmöglich, allen einzeln zu folgen, um zu erproben, was ihre Lehren taugen. So muss man eine Auswahl treffen. Die Persönlichkeit eines solchen Lehrers muss als besonders vertrauenswürdig erscheinen, so dass man sich auf ihn einlassen kann und will. Dieses Vertrauen, dieser Glaube ist der Inhalt der ersten Zuflucht, der Zuflucht zu Buddha.</p><p>Das Wesentliche für Buddhisten ist aber nicht eine Erlöserpersönlichkeit im Dass ihres Gekommenseins&quot;1, sondern das Wesentliche für Buddhisten ist die Erlösungslehre, die es dem Einzelnen ermöglicht, den Weg zur Erlösung selbst zu gehen und so Erlösung selbst zu verwirklichen. Dazu muss man von dieser Lehre vorläufig  d. h., solange man noch nicht aus eigener Erfahrung weiß, dass sie zum Ziel führt  so überzeugt sein, dass man die Energie aufbringt, diese Lehre auf ihren Wahrheitsgehalt zu testen. Dies ist der Inhalt der zweiten Zuflucht, der Zuflucht zur Lehre Buddhas oder dem Dharma/ Dhamma, wie diese Lehre auf Sanskrit bzw. Pāli heißt.</p><blockquote><p>1  Rudolf Bultmann (1884-1976): &quot;Entscheidend ist nur das Daß des Gekommenseins Jesu, nicht das Was, das heißt nicht die historisch verifizierbaren Daten seines Lebens und Wirkens.&quot;</p></blockquote><p>Auch der beste Lehrer und die beste Lehre sind für mich nutzlos, wenn sie für einen normalen Sterblichen nicht nachvollziehbar sind. Deshalb ist es wichtig, überzeugt zu sein, dass es auch andere auf diesem Weg geschafft haben. Dies ist der Inhalt der dritten Zuflucht, der Zuflucht zur Gemeinschaft derer, die auf dem Weg Buddhas zur Erlösung gelangt sind, auf Sanskrit bzw. Pāli zum Saṅgha.</p></blockquote><p>काशीं पत्स्ये गङ्गां द्रक्ष्यामि तत्र च मरिष्यामीति मन्यमानो मान्यो वृद्धनरः पुत्रांश्च पुत्रपुत्रांश्च धनं च तत्याज काशीं च प्राव्रजत् । एवं च रोध्यं दुःखं तरिष्यतीति मन्ये ॥२॥</p><blockquote><p>&quot;Ich will nach Benares gehen, den Ganges sehen und dort sterben.&quot; Mit diesem Gedanken hat der ehrenswerte alte Mann Söhne, Sohnessöhne und Besitz verlassen und ist nach Benares aufgebrochen. Ich denke, dass er so das zu beendene Leiden überwinden wird.</p></blockquote><p>कन्यां व्युवह तस्यां च पुत्रमजनयं महाधनं च लेभ एवं सुखमापेत्यतीते मुमोह । ततः प्रजज्ञौ सुखाद्दुःखं जायते तस्माल्लोकसुखमपि त्यजनीयं न च किंचिदिन्द्रियैः स्प्रष्टव्यमिति ॥३॥</p><blockquote><p>In der Vergangenheit täuschte ich mich, dass ich das Glück erreicht habe, da ich ein Mädchen geheiratet, mit ihr einen Sohn gezeugt, und großen Reichtum erworben hatte. Dann erkannte ich, dass auch Glück Leiden entsteht und man deshalb auch das Glück der Welt aufgeben und nichts mit seinen Sinnen berühren sollte.</p></blockquote><p>विक्रेयाणि विक्रीयापुत्रवैश्यो भिक्षुभ्यो विक्रयफलमददाद्दानपुण्यं चादत्त । एतत्कर्म स्तुत्यमिति भिक्षवः प्रोचुर्बुद्धिमन्तस्तु विकल्पयन्ति किमेवं कुर्वाणो वश्यः पुण्यं चकारेति ॥४॥</p><blockquote><p>Der sohnlose Vaiśya verkaufte Ware, schenkte Mönchen den Verkaufserlös und erhielt das Verdienst seiner Freigebigkeit. Die Mönche verkündeten, dass diese Tat lobenswert ist, Einsichtige aber bezweifeln, ob der so handelnde Vaiśya Verdienstvolles tat.</p></blockquote><p>गुरुभिः शिष्याः शासितव्याः शिष्यैरध्ययनमध्येतव्यम् ॥५॥</p><blockquote><p>Lehrer müssen die Schüler unterrichten, Schüler müssen ihr Pensum lernen.</p></blockquote><p><img src="'+t+'" alt=""><br> Abb.: बुद्धं शरणं गच्छामि<br> Pilger zum angeblichen Fußabdruck Buddhas auf dem Adams Peak (श्रीपाद), Sri Lanka<br> [Bildquelle: Sailing Nomad. -- <a href="http://www.flickr.com/photos/ryanwhisner/3076149134/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/ryanwhisner/3076149134/</a>. -- Zugriff am 2009-01-21. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p>',17)])])}const m=n(a,[["render",u]]);export{g as __pageData,m as default};
